INSERT INTO "tributes" ("id","name","message","image_url","email","phone","approved","created_at","approved_at","admin_notes") VALUES(4,'Anonymous','Great man who loved war history, donuts, and world travel. ',NULL,NULL,NULL,0,'2025-07-18 20:37:33',NULL,NULL);
INSERT INTO "tributes" ("id","name","message","image_url","email","phone","approved","created_at","approved_at","admin_notes") VALUES(5,'Anonymous','You shall be missed Peter',NULL,NULL,NULL,0,'2025-07-18 20:45:42',NULL,NULL);
INSERT INTO "tributes" ("id","name","message","image_url","email","phone","approved","created_at","approved_at","admin_notes") VALUES(6,'Anonymous','You shall be missed Peter','/api/images/tribute-1752871673393-wpvmbcfsi.jpeg',NULL,NULL,1,'2025-07-18 20:47:58','2025-07-20T00:06:37.029Z',NULL);
INSERT INTO "tributes" ("id","name","message","image_url","email","phone","approved","created_at","approved_at","admin_notes") VALUES(8,'Anonymous','I learnt about Peter''s passing away while studying abroad, for which Peter kindly wrote a reference letter supporting my application. For the years of my legal education, he has been the greatest teacher, mentor and friend. During the Vis moot, he always talked about how we students stand on the shoulder of giants from the Vis alumnis and families. Truthfully, Peter, if I have seen further, it is by standing on the shoulders of you.',NULL,'tomyan2033@gmail.com',NULL,1,'2025-07-19 12:35:49','2025-07-20T00:05:19.132Z',NULL);
INSERT INTO "tributes" ("id","name","message","image_url","email","phone","approved","created_at","approved_at","admin_notes") VALUES(9,'Francis Chan',replace(replace('From the time I knew Professor Rhodes when he taught me tort, to when I participated in the Vis moot, he was very kind to me. I had a subtle interest in tort, but I remember that he was the one who brought it alive. The way he described cases and their reasonings was with a passion that is unique to him. At the end of one of his tort lectures, he spoke to the cohort about the opportunity of the Vis moot. He told me it was great, so I went to the information session in Admiralty. Upon my arrival, I saw him standing inside the moot court in the GLC with a gentle and warm smile. “Oh! You came!” He said, and introduced me to moot alumni. \r\nA lot of his advice on punctuality, organisation and writing in plain english sticks in my head. It hits even harder now that he is longer around with us. His advice to me is extremely valuable, and I will take it with me as I continue on my career path. Professor. Rhodes has my full respect and admiration, and I can only aspire to be as calm, collected and intelligent in my career in the future. He always spoke fondly of his family, and so my thoughts are with them in these tough times. Rest well Professor Rhodes, thank you for everything.','\r',char(13)),'\n',char(10)),NULL,'francischanchakming@gmail.com','63295997',1,'2025-07-19 12:46:13','2025-07-20T00:02:56.517Z',NULL);
INSERT INTO "tributes" ("id","name","message","image_url","email","phone","approved","created_at","approved_at","admin_notes") VALUES(10,'Anonymous','I’ve never had the formal opportunity to introduce myself to Peter. I was one of his students at CUHK LLB, and every Friday at 9:30 am in the morning would sit, alone, at a corner at the back of his room at one of his lectures. He spoke life into those lectures. I left every lecture with a smile. He was, undoubtedly, my favourite professor through my four years at university. I thank him for his time, his patience, and his eloquence towards his students. Thank you, Professor Rhodes. ',NULL,NULL,NULL,1,'2025-07-19 12:59:25','2025-07-20T00:03:04.763Z',NULL);
INSERT INTO "tributes" ("id","name","message","image_url","email","phone","approved","created_at","approved_at","admin_notes") VALUES(11,'Anonymous','Tort might not be my best subject, but Peter was the best teacher. The attached photo was taken on 3 April 2024 at the end of the last lecture of the Tort 2 course at CUHK.','/api/images/tribute-1752935012206-w4eqx7o0k.jpeg',NULL,NULL,0,'2025-07-19 14:23:33',NULL,NULL);
INSERT INTO "tributes" ("id","name","message","image_url","email","phone","approved","created_at","approved_at","admin_notes") VALUES(12,'Gerald Lam',replace(replace('To us CUHK Vis mooters, and to me, Peter was not just a legal giant, he was and will always be family.  As one of the first mooters at the then-fledging CUHK Law faculty, he gave me and others more than a sense of purpose and drive.  He was not only our mentor and professor -- Peter and Connie opened their home to us and welcomed us as part of his family.  As someone who had then just arrived to Hong Kong and was unsure of my choice to develop a career here, his kindness solidified to me that I was right where I needed to be, and gave me the enduring confidence to both excel at the 2010 moot with my team, grow my career and to eventually settle and have a family of my own in Hong Kong.  To me, he epitomized kindness, the courage to stand up for others, to act in fairness and to always maintain high standards.  These are all attributes that I try to embrace every day of my career.  I will always remember his guidance during our practices, especially the one where we need to embrace our own selves and boil it down to "a respectful, courteous conversation with the arbitrators".  Who was I to argue with the former dean of HKU law?  I continue to carry myself in the same manner everyday, whether with opposing counsel, clients or others.  \r\n\r\nPeter you were more than our mentor, you were our friend.  We thank you for your courage to dedicate the latter part of your stellar career to us, and to make us more than the sum of our parts.  We helped the faculty obtain our very first Vis awards because of you (something that is a continuing pride for us even to this day)!  We are all where we are because of you.  Rest in peace.','\r',char(13)),'\n',char(10)),'/api/images/tribute-1752935859594-pcct3o5co.jpeg','geraldhclam@gmail.com',NULL,1,'2025-07-19 14:37:40','2025-07-20T00:02:34.698Z',NULL);
INSERT INTO "tributes" ("id","name","message","image_url","email","phone","approved","created_at","approved_at","admin_notes") VALUES(13,'Anderson Chen','Professor Peter Fredrick Rhodes’s profound wisdom in tort law transformed how I understand law and justice, but it was his boundless mindless and mentorship that forever changed how I think and live.',NULL,NULL,NULL,1,'2025-07-19 15:07:05','2025-07-20T00:02:31.578Z',NULL);
INSERT INTO "tributes" ("id","name","message","image_url","email","phone","approved","created_at","approved_at","admin_notes") VALUES(14,'Fontane Wong','Peter was a wonderful professor, coach, and mentor. I count myself fortunate to have been on his Vis moot team, which was the best part of my law school experience. I was never confident with my advocacy, but Peter believed in me even when I didn’t believe in myself. He taught me more than just law and advocacy, but values that continue to inspire me every day. From Peter, I learnt “attitude determines altitude” and to always strive for excellence. I was truly blessed to have him as my coach. He will be deeply missed and long remembered with love, respect, and gratitude.',NULL,NULL,NULL,1,'2025-07-19 16:18:52','2025-07-20T00:02:27.949Z',NULL);
INSERT INTO "tributes" ("id","name","message","image_url","email","phone","approved","created_at","approved_at","admin_notes") VALUES(15,'Anonymous','He was my favorite professor in CUHK ','/api/images/tribute-1752943291005-eu6zs3xfv.png','ambercaocst@gmail.com','85264784569',1,'2025-07-19 16:41:31','2025-07-20T00:02:23.635Z',NULL);
INSERT INTO "tributes" ("id","name","message","image_url","email","phone","approved","created_at","approved_at","admin_notes") VALUES(16,'Stephanie Poon',replace(replace('I brought my husband and three-year-old son back to the CUHK Faculty of Law for the first time since graduation the day before I learnt about the news that Peter has passed away. On the day when I visited the CUHK Faculty of Law, I was so touched and impressed that there was a “new” wall of Mooting Awards (which was not present in my days) with mooting certificates hung right outside the Moot Court of the Shatin campus. I still remember clearly that I thought to myself when I was admiring the large amount of certificates of Vis Moot certificates on the wall thinking that these were Peter’s efforts in nurturing and letting CUHK students achieve so much. \r\n\r\nPeter has been the most influential professor in my law school life. He always has the kindest smile on his face. He saw my passion in mooting and generously let me sit in the Vis team when I was just in Year 1 LLB, when I frankly couldn''t contribute much to the Vis team as an ignorant green fresher. I remember he always smiled at the tiny acts of my enthusiasm such as having already printed a 60-page memorandum in advance before the team distributed the hard copy during the Vis session.\r\n\r\nI only joined the Vis team officially in Year 2 LLB - back then, the Vis team has never admitted any member younger than Year 3 LLB, but Peter kindly made the exception for me. The second year of Vis team as an official member hit differently and has been a bit tough for me, but Peter didn’t give up on me - I still remember vividly that in our last debrief after we came back from Vienna, Peter (with his favourite Ricola candy in his mouth) said "Stephanie, what can I say, you were struggling at first but you eventually found your way to contribute to the team".\r\n\r\nI also remember that when chatting with team members from other Vis teams in both Vis East and Vis Vienna, many team members asked me how many people were in the CUHK team and I replied 12, and many gave me the response that our team was a big one. Thinking back, this is exactly what Peter wanted - to teach, influence and touch as many students’ lives as possible with the life-changing Vis Moot experience. \r\n\r\nThank you Peter, for giving me such a precious once-in-a-lifetime opportunity in law school of being a part of the Vis Family. Vis Moot has been the highlight of my law school life. When I reminisce the time I had at CUHK Law School, Vis Moot definitely comes first in my mind (in addition to the Sachertorte that Peter and Connie treated the Vis team in Vienna). \r\n\r\nWhen we met up for the 10th Vis Family reunion approximately ten years ago (?) which took place in a Chinese restaurant, Peter came to me to ask how I was doing. I told him that I missed Connie''s carrot cake the most about Vis. You can see his face lit up with joy saying that this was very sweet of me to say so and that no one has said this first thing to him. You can tell that he was very touched and can totally see the love he had for Connie. \r\n\r\nOutside of Vis, he is the best professor I have ever met - he makes tort law so memorable and fun for freshers, making every detail so relatable. Peter’s lectures are still vivid in my mind - he mentioned details of tort law cases such as Harland & Wolff is the company that built the Titanic, his favourite phrases such as "justice demands!" (saying it while pointing his index finger) and "deep pockets" (saying it while patting his own trousers pockets), always starting off tort tutorials with the news of the day etc., making tort so relatable to our daily lives.\r\n\r\nPeter will be missed. He is irreplaceable. His legacy will remain. The seeds of knowledge that he planted will grow forever. \r\n\r\nStephanie Poon (CUHK LLB Class of 2015)','\r',char(13)),'\n',char(10)),'/api/images/tribute-1752947131096-olakui4hm.jpeg','scypoon@hotmail.com','+85297467023',1,'2025-07-19 17:45:32','2025-07-20T00:02:17.837Z',NULL);
